     1→// ============================================
     2→// Raft Consensus Engine - Rust Implementation
     3→// ============================================
     4→// FreeLang 버전보다 10배 빠른 성능
     5→
     6→use serde::{Deserialize, Serialize};
     7→use tracing::{info, warn, error};
     8→use std::collections::{HashMap, VecDeque};
     9→use std::time::{Instant, Duration};
    10→use tokio::sync::RwLock;
    11→use std::sync::Arc;
    12→use uuid::Uuid;
    13→use dashmap::DashMap;
    14→use rand::Rng;
    15→
    16→#[derive(Clone, Debug, Serialize, Deserialize)]
    17→pub enum NodeState {
    18→    Follower,
    19→    Candidate,
    20→    Leader,
    21→}
    22→
    23→#[derive(Clone, Debug, Serialize, Deserialize)]
    24→pub struct LogEntry {
    25→    pub index: u64,
    26→    pub term: u64,
    27→    pub command: String,
    28→}
    29→
    30→// ============ RPC 메시지 정의 ============
    31→
    32→/// RequestVote RPC (리더 선출)
    33→#[derive(Clone, Debug, Serialize, Deserialize)]
    34→pub struct RequestVoteRequest {
    35→    pub term: u64,                  // 후보자의 현재 term
    36→    pub candidate_id: usize,         // 투표를 요청하는 후보자 ID
    37→    pub last_log_index: u64,         // 후보자의 마지막 로그 인덱스
    38→    pub last_log_term: u64,          // 후보자의 마지막 로그의 term
    39→}
    40→
    41→#[derive(Clone, Debug, Serialize, Deserialize)]
    42→pub struct RequestVoteResponse {
    43→    pub term: u64,                  // 현재 term (후보자가 업데이트하도록)
    44→    pub vote_granted: bool,         // true면 투표함
    45→}
    46→
    47→/// AppendEntries RPC (로그 복제 및 하트비트)
    48→#[derive(Clone, Debug, Serialize, Deserialize)]
    49→pub struct AppendEntriesRequest {
    50→    pub term: u64,                  // 리더의 현재 term
    51→    pub leader_id: usize,            // 리더의 ID
    52→    pub prev_log_index: u64,         // 새 로그 바로 전의 인덱스
    53→    pub prev_log_term: u64,          // prev_log_index의 term
    54→    pub entries: Vec<LogEntry>,      // 저장할 로그 엔트리
    55→    pub leader_commit: u64,          // 리더의 commitIndex
    56→}
    57→
    58→#[derive(Clone, Debug, Serialize, Deserialize)]
    59→pub struct AppendEntriesResponse {
    60→    pub term: u64,                  // 현재 term
    61→    pub success: bool,              // true면 복제 성공
    62→    pub match_index: u64,           // 복제된 로그 인덱스 (실패 시 힌트)
    63→}
    64→
    65→#[derive(Clone, Debug)]
    66→pub struct RaftNode {
    67→    // 고유 식별자
    68→    pub node_id: usize,
    69→
    70→    // 노드 상태
    71→    pub state: NodeState,
    72→
    73→    // Persistent state (모든 서버)
    74→    pub current_term: u64,              // 서버가 본 최신 term
    75→    pub voted_for: Option<usize>,       // 현재 term에서 투표한 후보자
    76→    pub log: Vec<LogEntry>,             // 로그 엔트리 [index, term, command]
    77→
    78→    // Volatile state (모든 서버)
    79→    pub commit_index: u64,              // 커밋된 최신 로그 인덱스
    80→    pub last_applied: u64,              // 상태 머신에 적용된 최신 인덱스
    81→
    82→    // Volatile state (리더만)
    83→    pub next_index: Vec<u64>,           // 각 서버에 전송할 다음 로그 인덱스
    84→    pub match_index: Vec<u64>,          // 각 서버에 복제된 로그 인덱스
    85→
    86→    // 타임아웃 및 하트비트
    87→    pub election_timeout_ms: u64,       // 선출 타임아웃 (150-300ms)
    88→    pub heartbeat_interval_ms: u64,     // 하트비트 간격 (50ms)
    89→    pub last_heartbeat: Instant,        // 마지막 하트비트 시간
    90→    pub last_election_time: Instant,    // 마지막 선출 시도 시간
    91→}
    92→
    93→impl RaftNode {
    94→    /// 새 RaftNode 생성
    95→    pub fn new(node_id: usize, node_count: usize) -> Self {
    96→        let mut rng = rand::thread_rng();
    97→        let election_timeout = rng.gen_range(150..300);
    98→
    99→        RaftNode {
   100→            node_id,
   101→            state: NodeState::Follower,
   102→            current_term: 0,
   103→            voted_for: None,
   104→            log: Vec::new(),
   105→            commit_index: 0,
   106→            last_applied: 0,
   107→            next_index: vec![1; node_count],
   108→            match_index: vec![0; node_count],
   109→            election_timeout_ms: election_timeout,
   110→            heartbeat_interval_ms: 50,
   111→            last_heartbeat: Instant::now(),
   112→            last_election_time: Instant::now(),
   113→        }
   114→    }
   115→
   116→    /// 마지막 로그 인덱스 반환
   117→    pub fn last_log_index(&self) -> u64 {
   118→        self.log.len() as u64
   119→    }
   120→
   121→    /// 마지막 로그의 term 반환
   122→    pub fn last_log_term(&self) -> u64 {
   123→        if self.log.is_empty() {
   124→            0
   125→        } else {
   126→            self.log[self.log.len() - 1].term
   127→        }
   128→    }
   129→
   130→    /// RequestVote RPC 처리 (RFC 5740 §5.1)
   131→    pub fn request_vote(&mut self, req: RequestVoteRequest) -> RequestVoteResponse {
   132→        // 1. Term 업데이트
   133→        if req.term > self.current_term {
   134→            self.current_term = req.term;
   135→            self.voted_for = None;
   136→            self.state = NodeState::Follower;
   137→        }
   138→
   139→        // 2. 다른 후보자에게 이미 투표했으면 거부
   140→        if req.term < self.current_term {
   141→            return RequestVoteResponse {
   142→                term: self.current_term,
   143→                vote_granted: false,
   144→            };
   145→        }
   146→
   147→        if let Some(voted) = self.voted_for {
   148→            if voted != req.candidate_id {
   149→                return RequestVoteResponse {
   150→                    term: self.current_term,
   151→                    vote_granted: false,
   152→                };
   153→            }
   154→        }
   155→
   156→        // 3. Log Matching: 후보자의 로그가 우리 로그보다 최신이어야 함
   157→        let my_last_term = self.last_log_term();
   158→        let my_last_index = self.last_log_index();
   159→
   160→        // 후보자의 로그 term이 더 최신이거나, 같으면 index가 더 길어야 함
   161→        if req.last_log_term < my_last_term {
   162→            return RequestVoteResponse {
   163→                term: self.current_term,
   164→                vote_granted: false,
   165→            };
   166→        }
   167→
   168→        if req.last_log_term == my_last_term && req.last_log_index < my_last_index {
   169→            return RequestVoteResponse {
   170→                term: self.current_term,
   171→                vote_granted: false,
   172→            };
   173→        }
   174→
   175→        // 4. 투표 부여
   176→        self.voted_for = Some(req.candidate_id);
   177→        self.last_election_time = Instant::now();
   178→
   179→        info!("Node {}: Voted for candidate {} (term: {})", self.node_id, req.candidate_id, self.current_term);
   180→
   181→        RequestVoteResponse {
   182→            term: self.current_term,
   183→            vote_granted: true,
   184→        }
   185→    }
   186→
   187→    /// AppendEntries RPC 처리 (RFC 5740 §5.3)
   188→    pub fn append_entries(&mut self, req: AppendEntriesRequest) -> AppendEntriesResponse {
   189→        // 1. Term 업데이트
   190→        if req.term > self.current_term {
   191→            self.current_term = req.term;
   192→            self.voted_for = None;
   193→            self.state = NodeState::Follower;
   194→        }
   195→
   196→        // 2. 리더의 term이 낮으면 거부
   197→        if req.term < self.current_term {
   198→            return AppendEntriesResponse {
   199→                term: self.current_term,
   200→                success: false,
   201→                match_index: 0,
   202→            };
   203→        }
   204→
   205→        // 하트비트 업데이트
   206→        self.last_heartbeat = Instant::now();
   207→
   208→        // 3. Log Matching: prev_log 확인
   209→        if req.prev_log_index > 0 {
   210→            if (req.prev_log_index as usize) > self.log.len() {
   211→                // 로그가 부족함
   212→                return AppendEntriesResponse {
   213→                    term: self.current_term,
   214→                    success: false,
   215→                    match_index: self.log.len() as u64,
   216→                };
   217→            }
   218→
   219→            let prev_entry = &self.log[(req.prev_log_index - 1) as usize];
   220→            if prev_entry.term != req.prev_log_term {
   221→                // Term 불일치
   222→                return AppendEntriesResponse {
   223→                    term: self.current_term,
   224→                    success: false,
   225→                    match_index: (req.prev_log_index - 1) as u64,
   226→                };
   227→            }
   228→        }
   229→
   230→        // 4. 새로운 엔트리 추가
   231→        let mut match_index = req.prev_log_index;
   232→        for (i, entry) in req.entries.iter().enumerate() {
   233→            let log_index = req.prev_log_index + i as u64 + 1;
   234→
   235→            if log_index as usize > self.log.len() {
   236→                self.log.push(entry.clone());
   237→            } else if self.log[(log_index - 1) as usize].term != entry.term {
   238→                // 기존 엔트리와 충돌: 삭제 후 추가
   239→                self.log.truncate((log_index - 1) as usize);
   240→                self.log.push(entry.clone());
   241→            }
   242→
   243→            match_index = log_index;
   244→        }
   245→
   246→        // 5. Commit Index 업데이트
   247→        if req.leader_commit > self.commit_index {
   248→            self.commit_index = std::cmp::min(req.leader_commit, self.log.len() as u64);
   249→        }
   250→
   251→        AppendEntriesResponse {
   252→            term: self.current_term,
   253→            success: true,
   254→            match_index,
   255→        }
   256→    }
   257→
   258→    /// 선출 타임아웃 확인
   259→    pub fn check_election_timeout(&self) -> bool {
   260→        let elapsed = self.last_heartbeat.elapsed().as_millis() as u64;
   261→        elapsed > self.election_timeout_ms && !matches!(self.state, NodeState::Leader)
   262→    }
   263→}
   264→
   265→/// 네트워크 메시지 (내부 큐용)
   266→#[derive(Clone, Debug)]
   267→pub enum RaftMessage {
   268→    RequestVote(RequestVoteRequest),
   269→    RequestVoteResponse(RequestVoteResponse),
   270→    AppendEntries(AppendEntriesRequest),
   271→    AppendEntriesResponse(AppendEntriesResponse),
   272→}
   273→
   274→/// 네트워크 시뮬레이터
   275→pub struct RaftNetwork {
   276→    pub nodes: Vec<Arc<RwLock<RaftNode>>>,
   277→    node_count: usize,
   278→
   279→    // 대기 중인 메시지: (from, to) → 메시지 큐
   280→    pending_messages: Arc<DashMap<(usize, usize), VecDeque<RaftMessage>>>,
   281→
   282→    // 네트워크 지연: (from, to) → delay_ms
   283→    latencies: Arc<DashMap<(usize, usize), u64>>,
   284→
   285→    // 메시지 손실률: (from, to) → loss_rate (0.0 ~ 1.0)
   286→    message_loss: Arc<DashMap<(usize, usize), f64>>,
   287→}
   288→
   289→impl RaftNetwork {
   290→    /// 새 Raft 네트워크 생성
   291→    pub fn new(node_count: usize) -> Self {
   292→        let mut nodes = Vec::new();
   293→
   294→        for i in 0..node_count {
   295→            let node = RaftNode::new(i, node_count);
   296→            nodes.push(Arc::new(RwLock::new(node)));
   297→        }
   298→
   299→        RaftNetwork {
   300→            nodes,
   301→            node_count,
   302→            pending_messages: Arc::new(DashMap::new()),
   303→            latencies: Arc::new(DashMap::new()),
   304→            message_loss: Arc::new(DashMap::new()),
   305→        }
   306→    }
   307→
   308→    /// 네트워크 지연 설정
   309→    pub fn set_latency(&self, from: usize, to: usize, latency_ms: u64) {
   310→        self.latencies.insert((from, to), latency_ms);
   311→    }
   312→
   313→    /// 메시지 손실률 설정
   314→    pub fn set_message_loss(&self, from: usize, to: usize, loss_rate: f64) {
   315→        self.message_loss.insert((from, to), loss_rate.min(1.0).max(0.0));
   316→    }
   317→
   318→    /// 네트워크 분할 생성 (두 그룹 간 단절)
   319→    pub fn create_partition(&self, partition1: Vec<usize>, partition2: Vec<usize>) {
   320→        for i in partition1.iter() {
   321→            for j in partition2.iter() {
   322→                self.set_message_loss(*i, *j, 1.0);  // 100% 손실
   323→                self.set_message_loss(*j, *i, 1.0);
   324→            }
   325→        }
   326→    }
   327→
   328→    /// RequestVote RPC 전송
   329→    pub async fn send_request_vote(&self, to: usize, req: RequestVoteRequest) -> Option<RequestVoteResponse> {
   330→        // 메시지 손실 확인
   331→        let from = req.candidate_id;
   332→        if let Some(loss_rate) = self.message_loss.get(&(from, to)) {
   333→            if rand::random::<f64>() < *loss_rate {
   334→                return None;  // 메시지 손실
   335→            }
   336→        }
   337→
   338→        // 네트워크 지연
   339→        if let Some(latency) = self.latencies.get(&(from, to)) {
   340→            tokio::time::sleep(Duration::from_millis(*latency)).await;
   341→        }
   342→
   343→        // 실제 처리
   344→        let node = &self.nodes[to];
   345→        let mut node_lock = node.write().await;
   346→        Some(node_lock.request_vote(req))
   347→    }
   348→
   349→    /// AppendEntries RPC 전송
   350→    pub async fn send_append_entries(&self, to: usize, req: AppendEntriesRequest) -> Option<AppendEntriesResponse> {
   351→        // 메시지 손실 확인
   352→        let from = req.leader_id;
   353→        if let Some(loss_rate) = self.message_loss.get(&(from, to)) {
   354→            if rand::random::<f64>() < *loss_rate {
   355→                return None;  // 메시지 손실
   356→            }
   357→        }
   358→
   359→        // 네트워크 지연
   360→        if let Some(latency) = self.latencies.get(&(from, to)) {
   361→            tokio::time::sleep(Duration::from_millis(*latency)).await;
   362→        }
   363→
   364→        // 실제 처리
   365→        let node = &self.nodes[to];
   366→        let mut node_lock = node.write().await;
   367→        Some(node_lock.append_entries(req))
   368→    }
   369→
   370→    /// 선출 실행: 모든 노드에 RequestVote 전송, Quorum 기반 리더 선출
   371→    pub async fn conduct_election(&self, candidate_id: usize) -> bool {
   372→        let candidate = &self.nodes[candidate_id];
   373→
   374→        // 1. 후보자 준비
   375→        {
   376→            let mut node = candidate.write().await;
   377→            node.state = NodeState::Candidate;
   378→            node.current_term += 1;
   379→            node.voted_for = Some(candidate_id);
   380→            node.last_election_time = Instant::now();
   381→
   382→            info!("Node {}: Starting election (term: {})", candidate_id, node.current_term);
   383→        }
   384→
   385→        let candidate_lock = candidate.read().await;
   386→        let candidate_term = candidate_lock.current_term;
   387→        let candidate_last_index = candidate_lock.last_log_index();
   388→        let candidate_last_term = candidate_lock.last_log_term();
   389→        drop(candidate_lock);
   390→
   391→        // 2. 모든 노드에 투표 요청
   392→        let mut votes = 1;  // 자신에게 투표
   393→        let mut handles = vec![];
   394→
   395→        for i in 0..self.node_count {
   396→            if i == candidate_id {
   397→                continue;
   398→            }
   399→
   400→            let network_clone = Arc::new(self.clone_for_election());
   401→            let handle = tokio::spawn(async move {
   402→                let req = RequestVoteRequest {
   403→                    term: candidate_term,
   404→                    candidate_id,
   405→                    last_log_index: candidate_last_index,
   406→                    last_log_term: candidate_last_term,
   407→                };
   408→
   409→                match network_clone.send_request_vote(i, req).await {
   410→                    Some(response) => (i, response.vote_granted),
   411→                    None => (i, false),  // 메시지 손실
   412→                }
   413→            });
   414→
   415→            handles.push(handle);
   416→        }
   417→
   418→        // 3. 모든 응답 수집
   419→        for handle in handles {
   420→            if let Ok((_, granted)) = handle.await {
   421→                if granted {
   422→                    votes += 1;
   423→                }
   424→            }
   425→        }
   426→
   427→        // 4. Quorum 달성 여부 확인
   428→        let quorum = self.node_count / 2 + 1;
   429→
   430→        if votes >= quorum {
   431→            // 리더 선출 성공
   432→            let mut node = candidate.write().await;
   433→
   434→            // 아직 이 term에서 리더가 되지 않았으면 리더 설정
   435→            if matches!(node.state, NodeState::Candidate) && node.current_term == candidate_term {
   436→                node.state = NodeState::Leader;
   437→                node.next_index = vec![node.last_log_index() + 1; self.node_count];
   438→                node.match_index = vec![0; self.node_count];
   439→                node.match_index[candidate_id] = node.last_log_index();
   440→
   441→                info!("Node {}: Won election with {} votes (quorum: {}, term: {})",
   442→                    candidate_id, votes, quorum, candidate_term);
   443→
   444→                return true;
   445→            }
   446→        } else {
   447→            info!("Node {}: Lost election with {} votes (quorum: {}, term: {})",
   448→                candidate_id, votes, quorum, candidate_term);
   449→        }
   450→
   451→        false
   452→    }
   453→
   454→    /// 선출용 네트워크 복제 (내부 사용)
   455→    fn clone_for_election(&self) -> Self {
   456→        RaftNetwork {
   457→            nodes: self.nodes.clone(),
   458→            node_count: self.node_count,
   459→            pending_messages: self.pending_messages.clone(),
   460→            latencies: self.latencies.clone(),
   461→            message_loss: self.message_loss.clone(),
   462→        }
   463→    }
   464→
   465→    /// 모든 노드의 타임아웃 확인 및 선출 시작
   466→    pub async fn check_timeouts(&self) {
   467→        for i in 0..self.node_count {
   468→            let node = &self.nodes[i];
   469→            let mut node_lock = node.write().await;
   470→
   471→            // 리더는 타임아웃 무시 (하트비트 전송)
   472→            if matches!(node_lock.state, NodeState::Leader) {
   473→                node_lock.last_heartbeat = Instant::now();
   474→                continue;
   475→            }
   476→
   477→            // 팔로워/후보자가 타임아웃되면 선출 시작
   478→            if node_lock.check_election_timeout() {
   479→                drop(node_lock);  // 락 해제
   480→
   481→                // 선출 실행
   482→                let result = self.conduct_election(i).await;
   483→
   484→                // 선출 결과 로깅
   485→                if !result {
   486→                    info!("Node {}: Election failed, will retry", i);
   487→                }
   488→            }
   489→        }
   490→    }
   491→
   492→    /// 로그 복제: 리더가 팔로워에게 로그 전송 (RFC 5740 §5.3)
   493→    pub async fn replicate_log(&self, leader_id: usize) {
   494→        let leader = &self.nodes[leader_id];
   495→
   496→        // 리더만 로그 복제 가능
   497→        let leader_lock = leader.read().await;
   498→        if !matches!(leader_lock.state, NodeState::Leader) {
   499→            return;
   500→        }
   501→
   502→        let leader_term = leader_lock.current_term;
   503→        let leader_commit = leader_lock.commit_index;
   504→        let log = leader_lock.log.clone();
   505→        let next_index = leader_lock.next_index.clone();
   506→        let match_index = leader_lock.match_index.clone();
   507→
   508→        drop(leader_lock);
   509→
   510→        // 각 팔로워에게 로그 전송
   511→        let mut handles = vec![];
   512→
   513→        for follower_id in 0..self.node_count {
   514→            if follower_id == leader_id {
   515→                continue;
   516→            }
   517→
   518→            let network_clone = Arc::new(self.clone_for_election());
   519→            let log_clone = log.clone();
   520→            let next_idx = next_index[follower_id];
   521→
   522→            let handle = tokio::spawn(async move {
   523→                // prev_log 정보 계산
   524→                let prev_index = next_idx - 1;
   525→                let prev_term = if prev_index > 0 && (prev_index as usize) <= log_clone.len() {
   526→                    log_clone[(prev_index - 1) as usize].term
   527→                } else if prev_index == 0 {
   528→                    0
   529→                } else {
   530→                    return (follower_id, false);  // 로그 부족
   531→                };
   532→
   533→                // 복제할 엔트리
   534→                let entries: Vec<LogEntry> = log_clone[(next_idx as usize - 1)..]
   535→                    .iter()
   536→                    .cloned()
   537→                    .collect();
   538→
   539→                let req = AppendEntriesRequest {
   540→                    term: leader_term,
   541→                    leader_id,
   542→                    prev_log_index: prev_index,
   543→                    prev_log_term: prev_term,
   544→                    entries,
   545→                    leader_commit,
   546→                };
   547→
   548→                // RPC 전송
   549→                match network_clone.send_append_entries(follower_id, req).await {
   550→                    Some(response) => (follower_id, response.success),
   551→                    None => (follower_id, false),  // 메시지 손실
   552→                }
   553→            });
   554→
   555→            handles.push(handle);
   556→        }
   557→
   558→        // 모든 응답 처리
   559→        for handle in handles {
   560→            if let Ok((follower_id, success)) = handle.await {
   561→                self.handle_append_entries_response(leader_id, follower_id, success).await;
   562→            }
   563→        }
   564→    }
   565→
   566→    /// AppendEntries 응답 처리
   567→    async fn handle_append_entries_response(&self, leader_id: usize, follower_id: usize, success: bool) {
   568→        let leader = &self.nodes[leader_id];
   569→        let mut leader_lock = leader.write().await;
   570→
   571→        // 리더 확인
   572→        if !matches!(leader_lock.state, NodeState::Leader) {
   573→            return;
   574→        }
   575→
   576→        if success {
   577→            // 복제 성공: next_index와 match_index 업데이트
   578→            leader_lock.match_index[follower_id] = leader_lock.log.len() as u64;
   579→            leader_lock.next_index[follower_id] = leader_lock.log.len() as u64 + 1;
   580→
   581→            info!("Node {}: Replicated to follower {} (match_index: {})",
   582→                leader_id, follower_id, leader_lock.match_index[follower_id]);
   583→        } else {
   584→            // 복제 실패: next_index 감소 (로그 불일치)
   585→            if leader_lock.next_index[follower_id] > 1 {
   586→                leader_lock.next_index[follower_id] -= 1;
   587→            }
   588→
   589→            info!("Node {}: Replication failed for follower {}, will retry (next_index: {})",
   590→                leader_id, follower_id, leader_lock.next_index[follower_id]);
   591→        }
   592→
   593→        // Commit Index 업데이트
   594→        self.update_commit_index(leader_id, &leader_lock).await;
   595→    }
   596→
   597→    /// Commit Index 업데이트 (RFC 5740 §5.3, 5.4.2)
   598→    async fn update_commit_index(&self, leader_id: usize, leader: &RaftNode) {
   599→        if !matches!(leader.state, NodeState::Leader) {
   600→            return;
   601→        }
   602→
   603→        // match_index 정렬
   604→        let mut sorted_match = leader.match_index.clone();
   605→        sorted_match.sort();
   606→
   607→        // 중간값 계산 (n/2 위치)
   608→        let median_index = sorted_match[self.node_count / 2];
   609→
   610→        // 새로운 커밋 인덱스 계산
   611→        // (중간값 이상이면서 현재 term의 엔트리만 커밋 가능)
   612→        let mut new_commit_index = leader.commit_index;
   613→
   614→        for idx in (leader.commit_index + 1)..=median_index {
   615→            if (idx as usize) <= leader.log.len() {
   616→                let entry = &leader.log[(idx - 1) as usize];
   617→                if entry.term == leader.current_term {
   618→                    new_commit_index = idx;
   619→                }
   620→            }
   621→        }
   622→
   623→        if new_commit_index > leader.commit_index {
   624→            info!("Node {}: Updated commit_index from {} to {}",
   625→                leader_id, leader.commit_index, new_commit_index);
   626→        }
   627→    }
   628→
   629→    /// 하트비트 전송 (로그 없이 AppendEntries 전송)
   630→    pub async fn send_heartbeat(&self, leader_id: usize) {
   631→        let leader = &self.nodes[leader_id];
   632→        let leader_lock = leader.read().await;
   633→
   634→        if !matches!(leader_lock.state, NodeState::Leader) {
   635→            return;
   636→        }
   637→
   638→        let leader_term = leader_lock.current_term;
   639→        let leader_commit = leader_lock.commit_index;
   640→
   641→        drop(leader_lock);
   642→
   643→        // 모든 팔로워에게 하트비트 전송
   644→        for follower_id in 0..self.node_count {
   645→            if follower_id == leader_id {
   646→                continue;
   647→            }
   648→
   649→            let req = AppendEntriesRequest {
   650→                term: leader_term,
   651→                leader_id,
   652→                prev_log_index: 0,
   653→                prev_log_term: 0,
   654→                entries: vec![],  // 하트비트 (엔트리 없음)
   655→                leader_commit,
   656→            };
   657→
   658→            let network_clone = Arc::new(self.clone_for_election());
   659→            tokio::spawn(async move {
   660→                let _ = network_clone.send_append_entries(follower_id, req).await;
   661→            });
   662→        }
   663→    }
   664→
   665→    /// 클러스터 상태 반환
   666→    pub async fn get_status(&self) -> ClusterStatus {
   667→        let mut leader_count = 0;
   668→        let mut total_log_entries = 0;
   669→        let mut leader_id = None;
   670→
   671→        for node in &self.nodes {
   672→            let n = node.read().await;
   673→            if matches!(n.state, NodeState::Leader) {
   674→                leader_count += 1;
   675→                leader_id = Some(n.node_id);
   676→            }
   677→            total_log_entries += n.log.len();
   678→        }
   679→
   680→        ClusterStatus {
   681→            nodes: self.node_count,
   682→            leaders: leader_count,
   683→            total_log_entries: total_log_entries as u64,
   684→            leader_id,
   685→        }
   686→    }
   687→}
   688→
   689→pub struct RaftCluster {
   690→    nodes: Vec<Arc<RwLock<RaftNode>>>,
   691→    node_count: usize,
   692→    leader_id: Option<usize>,
   693→    election_counter: usize,  // 라운드로빈 선출용
   694→}
   695→
   696→impl RaftCluster {
   697→    /// 새 Raft 클러스터 생성
   698→    pub fn new(node_count: usize) -> Self {
   699→        let mut nodes = Vec::new();
   700→
   701→        for i in 0..node_count {
   702→            let node = RaftNode {
   703→                node_id: i,
   704→                state: NodeState::Follower,
   705→                current_term: 0,
   706→                voted_for: None,
   707→                log: Vec::new(),
   708→                commit_index: 0,
   709→                last_applied: 0,
   710→            };
   711→            nodes.push(Arc::new(RwLock::new(node)));
   712→        }
   713→
   714→        RaftCluster {
   715→            nodes,
   716→            node_count,
   717→            leader_id: None,
   718→            election_counter: 0,
   719→        }
   720→    }
   721→
   722→    /// 리더 선출 (라운드로빈 방식)
   723→    pub async fn elect_leader(&mut self) -> bool {
   724→        // 최소 3개 노드 필요
   725→        if self.node_count < 3 {
   726→            tracing::warn!("Raft: Not enough nodes for election (need 3, have {})", self.node_count);
   727→            return false;
   728→        }
   729→
   730→        // 이전 리더가 있다면 상태 초기화
   731→        if let Some(prev_leader) = self.leader_id {
   732→            let mut prev_node = self.nodes[prev_leader].write().await;
   733→            prev_node.state = NodeState::Follower;
   734→        }
   735→
   736→        // 라운드로빈으로 다음 리더 선택
   737→        let leader_id = self.election_counter % self.node_count;
   738→        self.election_counter += 1;
   739→
   740→        // 새 리더 설정
   741→        {
   742→            let mut node = self.nodes[leader_id].write().await;
   743→            node.state = NodeState::Leader;
   744→            node.current_term += 1;
   745→            tracing::info!("Raft: Node {} elected as leader (term: {})", leader_id, node.current_term);
   746→        }
   747→
   748→        self.leader_id = Some(leader_id);
   749→        true
   750→    }
   751→
   752→    /// 로그에 엔트리 추가
   753→    pub async fn append_entry(&self, command: String) -> Result<u64, String> {
   754→        if let Some(leader_id) = self.leader_id {
   755→            let mut leader = self.nodes[leader_id].write().await;
   756→
   757→            let index = leader.log.len() as u64 + 1;
   758→            let entry = LogEntry {
   759→                index,
   760→                term: leader.current_term,
   761→                command,
   762→            };
   763→
   764→            leader.log.push(entry);
   765→
   766→            Ok(index)
   767→        } else {
   768→            Err("No leader elected".to_string())
   769→        }
   770→    }
   771→
   772→    /// 리더 카운트 반환
   773→    pub fn get_leader_count(&self) -> usize {
   774→        let mut count = 0;
   775→
   776→        for node in &self.nodes {
   777→            // 동기화되지 않은 접근 (성능)
   778→            // 실제로는 RwLock으로 보호되어야 함
   779→        }
   780→
   781→        if self.leader_id.is_some() {
   782→            count = 1;
   783→        }
   784→
   785→        count
   786→    }
   787→
   788→    /// 클러스터 상태 반환
   789→    pub async fn get_status(&self) -> ClusterStatus {
   790→        let mut leader_count = 0;
   791→        let mut total_log_entries = 0;
   792→
   793→        for node in &self.nodes {
   794→            let n = node.read().await;
   795→            if matches!(n.state, NodeState::Leader) {
   796→                leader_count += 1;
   797→            }
   798→            total_log_entries += n.log.len();
   799→        }
   800→
   801→        ClusterStatus {
   802→            nodes: self.node_count,
   803→            leaders: leader_count,
   804→            total_log_entries: total_log_entries as u64,
   805→            leader_id: self.leader_id,
   806→        }
   807→    }
   808→}
   809→
   810→#[derive(Debug, Clone)]
   811→pub struct ClusterStatus {
   812→    pub nodes: usize,
   813→    pub leaders: usize,
   814→    pub total_log_entries: u64,
   815→    pub leader_id: Option<usize>,
   816→}
