     2→// Load Balancer & Proxy - Rust Implementation
     3→// ============================================
     4→// 고성능 로드 밸런싱 및 프록시
     5→
     6→use std::sync::atomic::{AtomicUsize, Ordering};
     7→use std::sync::Arc;
     8→use dashmap::DashMap;
     9→use tracing::info;
    10→
    11→#[derive(Debug, Clone)]
    12→pub enum LoadBalancingStrategy {
    13→    RoundRobin,
    14→    LeastConnections,
    15→    Weighted,
    16→}
    17→
    18→pub struct Backend {
    19→    pub id: usize,
    20→    pub host: String,
    21→    pub port: u16,
    22→    pub weight: u32,
    23→    pub active: bool,
    24→    pub connection_count: Arc<AtomicUsize>,
    25→}
    26→
    27→pub struct ProxyServer {
    28→    listen_port: u16,
    29→    backends: Vec<Arc<Backend>>,
    30→    current_index: Arc<AtomicUsize>,
    31→    strategy: LoadBalancingStrategy,
    32→    metrics: Arc<ProxyMetrics>,
    33→}
    34→
    35→pub struct ProxyMetrics {
    36→    total_requests: Arc<AtomicUsize>,
    37→    successful_requests: Arc<AtomicUsize>,
    38→    failed_requests: Arc<AtomicUsize>,
    39→    total_latency: Arc<AtomicUsize>,
    40→}
    41→
    42→impl ProxyServer {
    43→    /// 새 프록시 서버 생성
    44→    pub fn new(port: u16) -> Self {
    45→        let backends = vec![
    46→            Arc::new(Backend {
    47→                id: 0,
    48→                host: "localhost".to_string(),
    49→                port: 9000,
    50→                weight: 1,
    51→                active: true,
    52→                connection_count: Arc::new(AtomicUsize::new(0)),
    53→            }),
    54→            Arc::new(Backend {
    55→                id: 1,
    56→                host: "localhost".to_string(),
    57→                port: 9100,
    58→                weight: 2,
    59→                active: true,
    60→                connection_count: Arc::new(AtomicUsize::new(0)),
    61→            }),
    62→            Arc::new(Backend {
    63→                id: 2,
    64→                host: "localhost".to_string(),
    65→                port: 9200,
    66→                weight: 1,
    67→                active: true,
    68→                connection_count: Arc::new(AtomicUsize::new(0)),
    69→            }),
    70→        ];
    71→
    72→        info!("🌐 Proxy Server initialized on port {}", port);
    73→        info!("   Backends: {}", backends.len());
    74→        info!("   Strategy: Round-Robin");
    75→
    76→        ProxyServer {
    77→            listen_port: port,
    78→            backends,
    79→            current_index: Arc::new(AtomicUsize::new(0)),
    80→            strategy: LoadBalancingStrategy::RoundRobin,
    81→            metrics: Arc::new(ProxyMetrics {
    82→                total_requests: Arc::new(AtomicUsize::new(0)),
    83→                successful_requests: Arc::new(AtomicUsize::new(0)),
    84→                failed_requests: Arc::new(AtomicUsize::new(0)),
    85→                total_latency: Arc::new(AtomicUsize::new(0)),
    86→            }),
    87→        }
    88→    }
    89→
    90→    /// 백엔드 선택 (Round-Robin)
    91→    pub fn select_backend(&self) -> Option<Arc<Backend>> {
    92→        if self.backends.is_empty() {
    93→            return None;
    94→        }
    95→
    96→        let index = self.current_index.fetch_add(1, Ordering::Relaxed);
    97→        let selected = index % self.backends.len();
    98→
    99→        Some(self.backends[selected].clone())
   100→    }
   101→
   102→    /// 최소 연결 백엔드 선택
   103→    pub fn select_backend_least_connections(&self) -> Option<Arc<Backend>> {
   104→        self.backends
   105→            .iter()
   106→            .min_by_key(|b| b.connection_count.load(Ordering::Relaxed))
   107→            .cloned()
   108→    }
   109→
   110→    /// 요청 처리
   111→    pub async fn handle_request(&self, request_id: usize) -> Result<(), String> {
   112→        // 요청 카운트 증가
   113→        self.metrics.total_requests.fetch_add(1, Ordering::Relaxed);
   114→
   115→        // 백엔드 선택
   116→        let backend = self.select_backend()
   117→            .ok_or_else(|| "No backends available".to_string())?;
   118→
   119→        // 연결 증가
   120→        backend.connection_count.fetch_add(1, Ordering::Relaxed);
   121→
   122→        // 요청 처리 시뮬레이션 (10-50ms)
   123→        let latency = 10 + (request_id % 40) as usize;
   124→        tokio::time::sleep(tokio::time::Duration::from_millis(latency as u64)).await;
   125→
   126→        // 연결 감소
   127→        backend.connection_count.fetch_sub(1, Ordering::Relaxed);
   128→
   129→        // 성공 카운트 증가 (95% 성공률)
   130→        if request_id % 100 < 95 {
   131→            self.metrics.successful_requests.fetch_add(1, Ordering::Relaxed);
   132→        } else {
   133→            self.metrics.failed_requests.fetch_add(1, Ordering::Relaxed);
   134→            return Err("Request failed".to_string());
   135→        }
   136→
   137→        // 지연시간 기록
   138→        self.metrics.total_latency.fetch_add(latency, Ordering::Relaxed);
   139→
   140→        Ok(())
   141→    }
   142→
   143→    /// 메트릭 조회
   144→    pub fn get_metrics(&self) -> ProxyMetricsSnapshot {
   145→        let total = self.metrics.total_requests.load(Ordering::Relaxed);
   146→        let successful = self.metrics.successful_requests.load(Ordering::Relaxed);
   147→        let failed = self.metrics.failed_requests.load(Ordering::Relaxed);
   148→        let total_latency = self.metrics.total_latency.load(Ordering::Relaxed);
   149→
   150→        let avg_latency = if total > 0 {
   151→            total_latency / total
   152→        } else {
   153→            0
   154→        };
   155→
   156→        ProxyMetricsSnapshot {
   157→            total_requests: total,
   158→            successful_requests: successful,
   159→            failed_requests: failed,
   160→            average_latency: avg_latency as u64,
   161→        }
   162→    }
   163→
   164→    /// 상태 보고
   165→    pub fn print_status(&self) {
   166→        let metrics = self.get_metrics();
   167→
   168→        info!("📊 Proxy Metrics:");
   169→        info!("├─ Total Requests: {}", metrics.total_requests);
   170→        info!("├─ Successful: {}", metrics.successful_requests);
   171→        info!("├─ Failed: {}", metrics.failed_requests);
   172→        info!("└─ Avg Latency: {}ms", metrics.average_latency);
   173→
   174→        info!("📈 Backend Status:");
   175→        for backend in &self.backends {
   176→            info!(
   177→                "  Node {}: {} connections (weight: {})",
   178→                backend.id,
   179→                backend.connection_count.load(Ordering::Relaxed),
   180→                backend.weight
   181→            );
   182→        }
   183→    }
   184→}
   185→
   186→impl Clone for ProxyServer {
   187→    fn clone(&self) -> Self {
   188→        ProxyServer {
   189→            listen_port: self.listen_port,
   190→            backends: self.backends.clone(),
   191→            current_index: self.current_index.clone(),
   192→            strategy: self.strategy.clone(),
   193→            metrics: self.metrics.clone(),
   194→        }
   195→    }
   196→}
   197→
   198→impl Clone for LoadBalancingStrategy {
   199→    fn clone(&self) -> Self {
   200→        match self {
   201→            LoadBalancingStrategy::RoundRobin => LoadBalancingStrategy::RoundRobin,
   202→            LoadBalancingStrategy::LeastConnections => LoadBalancingStrategy::LeastConnections,
   203→            LoadBalancingStrategy::Weighted => LoadBalancingStrategy::Weighted,
   204→        }
   205→    }
   206→}
   207→
   208→#[derive(Debug, Clone)]
   209→pub struct ProxyMetricsSnapshot {
   210→    pub total_requests: usize,
   211→    pub successful_requests: usize,
   212→    pub failed_requests: usize,
   213→    pub average_latency: u64,
   214→}
