    50→        let created_at = std::time::SystemTime::now()
    51→            .duration_since(std::time::UNIX_EPOCH)
    52→            .map(|d| d.as_secs())
    53→            .unwrap_or(0);  // 시간 생성 실패 시 0 사용 (거의 발생하지 않음)
    54→
    55→        let account = Account {
    56→            id: account_id.to_string(),
    57→            owner: format!("Owner of {}", account_id),
    58→            balance: initial_balance,
    59→            created_at,
    60→        };
    61→
    62→        self.accounts.insert(account_id.to_string(), account);
    63→        info!("✅ Account created: {}", account_id);
    64→    }
    65→
    66→    /// 계좌 조회
    67→    pub async fn get_account(&self, account_id: &str) -> Option<Account> {
    68→        self.accounts.get(account_id).map(|r| r.clone())
    69→    }
    70→
    71→    /// 송금
    72→    pub async fn transfer(
    73→        &self,
    74→        from: &str,
    75→        to: &str,
    76→        amount: i64,
    77→    ) -> Result<String, String> {
    78→        // 수수료 (50센트)
    79→        let fee = 50i64;
    80→        let total = amount + fee;
    81→
    82→        // 발신자 잔액 확인
    83→        let from_account = self
    84→            .accounts
    85→            .get_mut(from)
    86→            .ok_or_else(|| "Sender account not found".to_string())?;
    87→
    88→        if from_account.balance < total {
    89→            return Err("Insufficient balance".to_string());
    90→        }
    91→
    92→        from_account.balance -= total;
    93→
    94→        // 수신자 잔액 업데이트
    95→        if let Some(mut to_account) = self.accounts.get_mut(to) {
    96→            to_account.balance += amount;
    97→        } else {
    98→            return Err("Recipient account not found".to_string());
    99→        }
   100→
   101→        // 거래 기록
   102→        let tx_id = Uuid::new_v4().to_string();
   103→
   104→        let timestamp = std::time::SystemTime::now()
   105→            .duration_since(std::time::UNIX_EPOCH)
   106→            .map(|d| d.as_secs())
   107→            .unwrap_or(0);  // 시간 생성 실패 시 0 사용
   108→
   109→        let transaction = Transaction {
   110→            tx_id: tx_id.clone(),
   111→            from: from.to_string(),
   112→            to: to.to_string(),
   113→            amount,
   114→            timestamp,
   115→            status: "completed".to_string(),
   116→        };
   117→
   118→        {
   119→            let mut txs = self.transactions.write().await;
   120→            txs.push(transaction);
   121→        }
   122→
   123→        self.total_transactions
   124→            .fetch_add(1, std::sync::atomic::Ordering::Relaxed);
   125→
   126→        info!(
   127→            "✅ Transfer: {} -> {} ({} cents)",
   128→            from, to, amount
   129→        );
   130→
   131→        Ok(tx_id)
   132→    }
   133→
   134→    /// 입금
   135→    pub async fn deposit(&self, account_id: &str, amount: i64) -> Result<(), String> {
   136→        if let Some(mut account) = self.accounts.get_mut(account_id) {
   137→            account.balance += amount;
   138→            info!("✅ Deposit: {} ({} cents)", account_id, amount);
   139→            Ok(())
   140→        } else {
   141→            Err("Account not found".to_string())
   142→        }
   143→    }
   144→
   145→    /// 출금
   146→    pub async fn withdraw(&self, account_id: &str, amount: i64) -> Result<(), String> {
   147→        if let Some(mut account) = self.accounts.get_mut(account_id) {
   148→            if account.balance < amount {
   149→                return Err("Insufficient balance".to_string());
   150→            }
   151→
   152→            account.balance -= amount;
   153→            info!("✅ Withdrawal: {} ({} cents)", account_id, amount);
   154→            Ok(())
   155→        } else {
   156→            Err("Account not found".to_string())
   157→        }
   158→    }
   159→
   160→    /// 거래 조회
   161→    pub async fn get_transactions(&self) -> Vec<Transaction> {
   162→        self.transactions.read().await.clone()
   163→    }
   164→
   165→    /// 통계
   166→    pub fn get_stats(&self) -> BankStats {
   167→        let total_accounts = self.accounts.len();
   168→        let total_transactions = self
   169→            .total_transactions
   170→            .load(std::sync::atomic::Ordering::Relaxed);
   171→
   172→        let total_balance: i64 = self
   173→            .accounts
   174→            .iter()
   175→            .map(|entry| entry.value().balance)
   176→            .sum();
   177→
   178→        BankStats {
   179→            total_accounts,
   180→            total_transactions,
   181→            total_balance,
   182→        }
   183→    }
   184→
   185→    /// 상태 보고
   186→    pub fn print_status(&self) {
   187→        let stats = self.get_stats();
   188→
   189→        info!("\n💰 Bank Statistics:");
   190→        info!("├─ Total Accounts: {}", stats.total_accounts);
   191→        info!("├─ Total Transactions: {}", stats.total_transactions);
   192→        info!("└─ Total Balance: ${:.2}", stats.total_balance as f64 / 100.0);
   193→    }
   194→}
   195→
   196→impl Clone for BankSystem {
   197→    fn clone(&self) -> Self {
   198→        BankSystem {
   199→            accounts: self.accounts.clone(),
   200→            transactions: self.transactions.clone(),
   201→            total_transactions: self.total_transactions.clone(),
   202→        }
   203→    }
   204→}
