     1→// ============================================
     2→// JWT Authentication Module
     3→// ============================================
     4→// JWT 토큰 기반 인증 시스템
     5→
     6→use chrono::Utc;
     7→use serde::{Deserialize, Serialize};
     8→use std::collections::HashMap;
     9→use std::sync::Arc;
    10→use tracing::info;
    11→
    12→/// 인증 토큰
    13→#[derive(Debug, Clone, Serialize, Deserialize)]
    14→pub struct AuthToken {
    15→    pub token: String,
    16→    pub user_id: String,
    17→    pub role: String,
    18→    pub issued_at: u64,
    19→    pub expires_at: u64,
    20→    pub scope: Vec<String>,
    21→}
    22→
    23→/// JWT 클레임
    24→#[derive(Debug, Clone, Serialize, Deserialize)]
    25→pub struct Claims {
    26→    pub sub: String,              // Subject (user_id)
    27→    pub role: String,             // Role
    28→    pub scope: Vec<String>,       // Scope
    29→    pub iat: u64,                 // Issued at
    30→    pub exp: u64,                 // Expiration
    31→}
    32→
    33→/// 토큰 검증기
    34→pub struct TokenValidator {
    35→    secret: String,
    36→    token_lifetime: u64,          // 초 단위
    37→    valid_tokens: Arc<HashMap<String, AuthToken>>,
    38→}
    39→
    40→impl TokenValidator {
    41→    /// 토큰 검증기 생성
    42→    pub fn new(secret: &str) -> Self {
    43→        info!("🔐 Token Validator initialized");
    44→
    45→        TokenValidator {
    46→            secret: secret.to_string(),
    47→            token_lifetime: 3600,  // 1시간
    48→            valid_tokens: Arc::new(HashMap::new()),
    49→        }
    50→    }
    51→
    52→    /// 토큰 생성
    53→    pub fn generate(&self, user_id: &str, role: &str) -> String {
    54→        let now = Utc::now().timestamp() as u64;
    55→        let exp = now + self.token_lifetime;
    56→
    57→        // 간단한 토큰 생성 (실제는 JWT 라이브러리 사용)
    58→        let claims = Claims {
    59→            sub: user_id.to_string(),
    60→            role: role.to_string(),
    61→            scope: vec!["read".to_string(), "write".to_string()],
    62→            iat: now,
    63→            exp,
    64→        };
    65→
    66→        // Base64 인코딩된 토큰 생성 (실제로는 JWT 서명)
    67→        let token_str = format!(
    68→            "{}.{}.{}",
    69→            base64_encode(&claims.sub),
    70→            base64_encode(&claims.role),
    71→            base64_encode(&self.secret)
    72→        );
    73→
    74→        info!("✅ Token generated for user: {}", user_id);
    75→
    76→        token_str
    77→    }
    78→
    79→    /// 토큰 검증
    80→    pub fn validate(&self, token: &str) -> Result<AuthToken, String> {
    81→        let parts: Vec<&str> = token.split('.').collect();
    82→        if parts.len() != 3 {
    83→            return Err("Invalid token format".to_string());
    84→        }
    85→
    86→        // Base64 디코딩 (실제는 JWT 검증)
    87→        let user_id = base64_decode(parts[0])
    88→            .map_err(|_| "Invalid token: user_id".to_string())?;
    89→        let role = base64_decode(parts[1])
    90→            .map_err(|_| "Invalid token: role".to_string())?;
    91→
    92→        let now = Utc::now().timestamp() as u64;
    93→
    94→        let auth_token = AuthToken {
    95→            token: token.to_string(),
    96→            user_id,
    97→            role,
    98→            issued_at: now,
    99→            expires_at: now + self.token_lifetime,
   100→            scope: vec!["read".to_string(), "write".to_string()],
   101→        };
   102→
   103→        info!("✅ Token validated for user: {}", auth_token.user_id);
   104→
   105→        Ok(auth_token)
   106→    }
   107→
   108→    /// 토큰 갱신
   109→    pub fn refresh(&self, token: &str) -> Result<String, String> {
   110→        let auth_token = self.validate(token)?;
   111→        Ok(self.generate(&auth_token.user_id, &auth_token.role))
   112→    }
   113→
   114→    /// 토큰 폐기
   115→    pub fn revoke(&self, token: &str) -> Result<(), String> {
   116→        info!("🔓 Token revoked: {}", token);
   117→        Ok(())
   118→    }
   119→
   120→    /// 권한 확인
   121→    pub fn check_permission(&self, token: &str, required_scope: &str) -> Result<bool, String> {
   122→        let auth_token = self.validate(token)?;
   123→
   124→        let has_permission = auth_token.scope.iter()
   125→            .any(|s| s == required_scope);
   126→
   127→        if has_permission {
   128→            info!("✅ Permission granted: {}", required_scope);
   129→        } else {
   130→            info!("❌ Permission denied: {}", required_scope);
   131→        }
   132→
   133→        Ok(has_permission)
   134→    }
   135→
   136→    /// 역할 확인
   137→    pub fn check_role(&self, token: &str, required_role: &str) -> Result<bool, String> {
   138→        let auth_token = self.validate(token)?;
   139→        Ok(auth_token.role == required_role)
   140→    }
   141→
   142→    /// 역할별 권한 조회
   143→    pub fn get_permissions_for_role(role: &str) -> Vec<String> {
   144→        match role {
   145→            "admin" => vec![
   146→                "read".to_string(),
   147→                "write".to_string(),
   148→                "delete".to_string(),
   149→                "manage_users".to_string(),
   150→            ],
   151→            "user" => vec![
   152→                "read".to_string(),
   153→                "write".to_string(),
   154→            ],
   155→            "guest" => vec![
   156→                "read".to_string(),
   157→            ],
   158→            _ => vec![],
   159→        }
   160→    }
   161→
   162→    /// 토큰 만료 확인
   163→    pub fn is_expired(&self, expires_at: u64) -> bool {
   164→        let now = Utc::now().timestamp() as u64;
   165→        now >= expires_at
   166→    }
   167→}
   168→
   169→/// Base64 인코딩 (간단한 구현)
   170→fn base64_encode(data: &str) -> String {
   171→    use std::str;
   172→    let bytes = data.as_bytes();
   173→    let mut result = String::new();
   174→
   175→    for &byte in bytes {
   176→        result.push_str(&format!("{:02x}", byte));
   177→    }
   178→
   179→    result
   180→}
   181→
   182→/// Base64 디코딩 (간단한 구현)
   183→fn base64_decode(encoded: &str) -> Result<String, String> {
   184→    let mut result = String::new();
   185→
   186→    let bytes: Vec<u8> = (0..encoded.len())
   187→        .step_by(2)
   188→        .map(|i| {
   189→            u8::from_str_radix(&encoded[i..i+2], 16)
   190→                .unwrap_or(0)
   191→        })
   192→        .collect();
   193→
   194→    result = String::from_utf8(bytes)
   195→        .map_err(|_| "Invalid UTF-8".to_string())?;
   196→
   197→    Ok(result)
   198→}
