   153→/// 메시지 인증 코드 (MAC)
   154→pub struct MessageAuthenticationCode {
   155→    pub tag: Vec<u8>,
   156→    pub algorithm: String,
   157→}
   158→
   159→impl MessageAuthenticationCode {
   160→    /// MAC 생성
   161→    pub fn generate(key: &[u8], message: &[u8]) -> Self {
   162→        // 간단한 HMAC 구현 (실제로는 HMAC-SHA256 사용)
   163→        let mut tag = vec![0u8; 32];
   164→        for (i, byte) in message.iter().enumerate() {
   165→            tag[i % 32] = tag[i % 32] ^ byte ^ key[i % key.len()];
   166→        }
   167→
   168→        MessageAuthenticationCode {
   169→            tag,
   170→            algorithm: "HMAC-SHA256".to_string(),
   171→        }
   172→    }
   173→
   174→    /// MAC 검증
   175→    pub fn verify(&self, key: &[u8], message: &[u8]) -> bool {
   176→        let expected = Self::generate(key, message);
   177→        expected.tag == self.tag
   178→    }
   179→}
